To build a Node.js application that recommends a list of restaurants between two street addresses, you can use the following APIs:

1. Google Maps API: For geocoding the street addresses, calculating driving distances, and searching for restaurants.
2. Yelp API (optional): To fetch more information about the restaurants and filter the results.

Here is a simple implementation using Express.js:

1. First, install the required packages:
```bash
npm init -y
npm install express request googleapis yelp-fusion
```
1. Create an `index.js` file and implement the following code:
```javascript
const express = require('express');
const request = require('request');
const { google } = require('googleapis');
const yelp = require('yelp-fusion');

const app = express();
const apiKey = 'YOUR_GOOGLE_MAPS_API_KEY';
const yelpApiKey = 'YOUR_YELP_API_KEY';
const yelpClient = yelp.client(yelpApiKey);

app.use(express.json());

async function getGeoCoordinates(address) {
  const maps = google.maps({ version: '3.44', apiKey });
  const geocoder = new maps.Geocoder();

  try {
    const result = await geocoder.geocode({ address });
    return result.results[0].geometry.location;
  } catch (error) {
    console.error(error);
  }
}

async function getRestaurants(midpoint) {
  try {
    const response = await yelpClient.search({
      term: 'restaurant',
      latitude: midpoint.lat,
      longitude: midpoint.lng,
      radius: 5000, // You can adjust the radius as needed
      sort_by: 'best_match',
    });

    return response.jsonBody.businesses;
  } catch (error) {
    console.error(error);
  }
}

app.post('/recommendations', async (req, res) => {
  try {
    const { address1, address2 } = req.body;

    const coord1 = await getGeoCoordinates(address1);
    const coord2 = await getGeoCoordinates(address2);

    const midpoint = {
      lat: (coord1.lat + coord2.lat) / 2,
      lng: (coord1.lng + coord2.lng) / 2,
    };

    const restaurants = await getRestaurants(midpoint);

    res.json(restaurants);
  } catch (error) {
    console.error(error);
    res.status(500).json({ error: 'An error occurred' });
  }
});

const PORT = process.env.PORT || 3000;
app.listen(PORT, () => console.log(`Server is running on port ${PORT}`));
```
Replace `'YOUR_GOOGLE_MAPS_API_KEY'` and `'YOUR_YELP_API_KEY'` with your respective API keys. You can obtain these keys by signing up for a Google Cloud Platform account and a Yelp Fusion API account.

Now, you can run the application:
```bash
node index.js
```
Send a POST request to the `/recommendations` endpoint with the following JSON payload:
```json
{
  "address1": "1600 Amphitheatre Parkway, Mountain View, CA",
  "address2": "1 Infinite Loop, Cupertino, CA"
}
```
The application will return a list of recommended restaurants approximately equal driving distance between the two addresses.

